  2→import React, { useState, useEffect } from 'react';
  3→import { createPortal } from 'react-dom';
  4→import { User } from '../types';
  5→import { Check, Download, ArrowLeft, ShieldCheck, LayoutList, History, FileText, Zap, Database, Fuel, Droplet, CreditCard, Star, Loader2, Sparkles, ArrowUpRight } from 'lucide-react';
  6→import jsPDF from 'jspdf';
