  8→import PageHeader from '../components/layout/PageHeader';
  9→
 10→interface PlanProps {
 11→  onBack: () => void;
 12→  user: User | null;
 13→  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
 14→  initialTab?: 'my-plan' | 'pricing' | 'billing';
 15→}
 16→
 17→const Plan: React.FC<PlanProps> = ({ onBack, user, onUpgrade, initialTab = 'my-plan' }) => {
 18→  const [activeTab, setActiveTab] = useState<'my-plan' | 'pricing' | 'billing'>(initialTab);
 19→  const [isProcessing, setIsProcessing] = useState(false);
 20→  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
 21→  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
 22→  const [paidAmount, setPaidAmount] = useState(0);
 23→  const [paymentHistory, setPaymentHistory] = useState([
 24→    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 25→    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 26→    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
 27→  ]);
 28→
 29→  useEffect(() => {
 30→    setActiveTab(initialTab);
 31→  }, [initialTab]);
 32→
 33→  useEffect(() => {
 34→    if (upgradeModal && paymentStep === 'success') { document.body.style.overflow = 'hidden'; }
 35→    return () => { document.body.style.overflow = ''; };
 36→  }, [upgradeModal, paymentStep]);
 37→
 38→  const plans = [
 39→    {
 40→      id: 'free',
 41→      name: 'Starter',
 42→      price: 29,
 43→      period: '/mois',
 44→      icon: <Droplet size={24} />,
 45→      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
 46→      cta: 'Plan Actuel',
 47→      current: user?.plan === 'free'
 48→    },
 49→    {
 50→      id: 'pro',
 51→      name: 'Pro',
 52→      price: 89,
 53→      period: '/mois',
 54→      icon: <Fuel size={24} />,
 55→      popular: true,
 56→      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
 57→      cta: 'Passer Pro',
 58→      current: user?.plan === 'pro'
 59→    },
 60→    {
 61→      id: 'enterprise',
 62→      name: 'Agency',
 63→      price: 299,
 64→      period: '/mois',
 65→      icon: <Database size={24} />,
 66→      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
 67→      cta: 'Passer Agency',
 68→      current: user?.plan === 'enterprise'
 69→    }
 70→  ];
 71→
 72→  const currentPlanPrice = user?.plan === 'enterprise' ? 299 : user?.plan === 'pro' ? 89 : 29;
 73→  const currentPlanName = user?.plan === 'enterprise' ? 'Agency' : user?.plan === 'pro' ? 'Pro' : 'Starter';
 74→
 75→  const handleUpgradeClick = (planId: string) => {
 76→    const targetPlan = plans.find(p => p.id === planId);
 77→    if (!targetPlan || targetPlan.current) return;
 78→    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
 79→    setPaymentStep('payment');
 80→  };
 81→
 82→  const handleProcessPayment = () => {
 83→    if (!upgradeModal) return;
 84→    setIsProcessing(true);
